html:
{% set supplier = frappe.get_doc("Supplier", doc.supplier) %}
{% set vendor_category = supplier.custom_vendor_category or "N/A" %}
{% set vendor_rating = supplier.custom_vendor_rating or 0 %}
{% set stars = vendor_rating | rating_to_stars %}
{% set is_low_rating = vendor_rating > 0 and vendor_rating < 3 %}

<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <style>
        body { font-family: Arial, sans-serif; font-size: 12px; color: #333; margin: 0; }
        .header { display: flex; justify-content: space-between; align-items: flex-start;
                  padding: 20px 0; border-bottom: 2px solid #333; margin-bottom: 20px; }
        .company-name { font-size: 20px; font-weight: bold; }
        .po-title { font-size: 24px; font-weight: bold; color: #2490EF; }
        .po-meta { margin-bottom: 20px; }
        .po-meta table { width: 100%; }
        .po-meta td { padding: 3px 8px; }
        .vendor-box { border: 1px solid #e0e0e0; border-radius: 6px;
                      padding: 12px 16px; margin: 12px 0; background: #fafafa; }
        .vendor-box .row { display: flex; gap: 32px; }
        .vendor-box .field { }
        .vendor-box .lbl { font-size: 10px; text-transform: uppercase;
                           letter-spacing: 0.08em; color: #888; margin-bottom: 2px; }
        .vendor-box .val { font-size: 14px; font-weight: 600; }
        .stars { color: #F4C542; font-size: 16px; letter-spacing: -1px; }
        .low-note { background: #FFF3CD; border: 1px solid #FFD93D;
                    border-radius: 6px; padding: 8px 12px; font-size: 11px;
                    color: #856404; margin: 8px 0; }
        table.items { width: 100%; border-collapse: collapse; margin: 16px 0; }
        table.items th { background: #2490EF; color: #fff; padding: 8px 10px;
                         text-align: left; font-size: 11px; text-transform: uppercase; }
        table.items td { padding: 8px 10px; border-bottom: 1px solid #f0f0f0; }
        table.items tr:nth-child(even) td { background: #f9f9f9; }
        .totals { float: right; margin-top: 10px; min-width: 280px; }
        .totals table { width: 100%; border-collapse: collapse; }
        .totals td { padding: 5px 10px; }
        .totals .grand { font-weight: bold; font-size: 14px;
                          background: #2490EF; color: #fff; border-radius: 4px; }
        .watermark { position: fixed; bottom: 40px; right: 40px; font-size: 10px;
                     color: #ddd; text-transform: uppercase; letter-spacing: 0.15em;
                     font-weight: 600; transform: rotate(-30deg); opacity: 0.5; }
        .footer { margin-top: 40px; padding-top: 12px; border-top: 1px solid #e0e0e0;
                  font-size: 10px; color: #aaa; text-align: center; }
    </style>
</head>
<body>

<!-- Watermark -->
<div class="watermark">Vendor Portal</div>

<!-- Header -->
<div class="header">
    <div>
        <div class="company-name">{{ doc.company }}</div>
        <div style="font-size:11px; color:#888; margin-top:4px;">
            {{ doc.company_address or "" }}
        </div>
    </div>
    <div style="text-align:right;">
        <div class="po-title">Purchase Order</div>
        <div style="font-size:14px; font-weight:600; color:#555;">{{ doc.name }}</div>
    </div>
</div>

<!-- PO Meta -->
<div class="po-meta">
    <table>
        <tr>
            <td><strong>Date:</strong> {{ doc.transaction_date }}</td>
            <td><strong>Expected Delivery:</strong> {{ doc.schedule_date or "—" }}</td>
            <td><strong>Status:</strong> {{ doc.status }}</td>
        </tr>
        <tr>
            <td colspan="3"><strong>Supplier:</strong> {{ doc.supplier_name }} ({{ doc.supplier }})</td>
        </tr>
    </table>
</div>

<!-- Vendor Info Box -->
<div class="vendor-box">
    <div style="font-size:11px; font-weight:600; text-transform:uppercase;
                letter-spacing:0.08em; color:#2490EF; margin-bottom:10px;">
        Vendor Information
    </div>
    <div class="row">
        <div class="field">
            <div class="lbl">Vendor Category</div>
            <div class="val">{{ vendor_category }}</div>
        </div>
        <div class="field">
            <div class="lbl">Vendor Rating</div>
            <div class="val">
                <span class="stars">{{ stars }}</span>
                <span style="font-size:13px; color:#555; margin-left:6px;">
                    {{ "%.1f"|format(vendor_rating) }}/5
                </span>
            </div>
        </div>
        <div class="field">
            <div class="lbl">Total Ratings</div>
            <div class="val">{{ supplier.custom_total_rating_count or 0 }}</div>
        </div>
    </div>
</div>

<!-- Low Rating Warning -->
{% if is_low_rating %}
<div class="low-note">
    ⚠️ Caution: This is a low-rated vendor ({{ "%.1f"|format(vendor_rating) }}/5).
    Please review vendor performance before proceeding.
</div>
{% endif %}

<!-- Items Table -->
<table class="items">
    <thead>
        <tr>
            <th>#</th>
            <th>Item Code</th>
            <th>Description</th>
            <th>Qty</th>
            <th>UOM</th>
            <th>Rate</th>
            <th>Amount</th>
        </tr>
    </thead>
    <tbody>
        {% for item in doc.items %}
        <tr>
            <td>{{ loop.index }}</td>
            <td>{{ item.item_code }}</td>
            <td>{{ item.item_name }}</td>
            <td>{{ item.qty }}</td>
            <td>{{ item.uom }}</td>
            <td style="text-align:right;">{{ frappe.format(item.rate, {"fieldtype":"Currency"}) }}</td>
            <td style="text-align:right;">{{ frappe.format(item.amount, {"fieldtype":"Currency"}) }}</td>
        </tr>
        {% endfor %}
    </tbody>
</table>

<!-- Totals -->
<div class="totals">
    <table>
        <tr>
            <td>Net Total</td>
            <td style="text-align:right;">{{ frappe.format(doc.net_total, {"fieldtype":"Currency"}) }}</td>
        </tr>
        {% if doc.total_taxes_and_charges %}
        <tr>
            <td>Taxes & Charges</td>
            <td style="text-align:right;">{{ frappe.format(doc.total_taxes_and_charges, {"fieldtype":"Currency"}) }}</td>
        </tr>
        {% endif %}
        <tr class="grand">
            <td style="padding:6px 10px;">Grand Total</td>
            <td style="text-align:right; padding:6px 10px;">
                {{ frappe.format(doc.grand_total, {"fieldtype":"Currency"}) }}
            </td>
        </tr>
    </table>
</div>

<div style="clear:both;"></div>

<!-- Terms & Conditions -->
{% if doc.terms %}
<div style="margin-top:30px; font-size:11px; color:#666;">
    <strong>Terms & Conditions:</strong><br>
    {{ doc.terms }}
</div>
{% endif %}

<!-- Footer -->
<div class="footer">
    Generated by Vendor Portal &bull; {{ doc.company }} &bull; {{ doc.transaction_date }}
</div>

</body>
</html>
